import { CCol, CForm, CFormInput, CContainer, CRow } from '@coreui/react';
import React from 'react';
import TextArea from '../common/TextArea';

const MagazineComponent = () => {
    return (
        <CContainer className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
            <CRow className="w-90" >
                <CCol md={12}>
                    <CForm>
                        <CFormInput
                            type="Title"
                            id="exampleFormControlInput1"
                            label="Email address"
                            placeholder="name@example.com"
                            text="Must be 8-20 characters long."
                            aria-describedby="exampleFormControlInputHelpInline"
                        />
                    </CForm>
                </CCol>
                <CCol md={12}>
                    {/* <CForm>
                        <CFormInput
                            type="Title"
                            id="exampleFormControlInput2"
                            label="Email address"
                            placeholder="name@example.com"
                            text="Must be 8-20 characters long."
                            aria-describedby="exampleFormControlInputHelpInline"
                        />
                    </CForm> */}
                     <TextArea
                            // value={formData?.metaDescription}
                            label={"Meta Description"}
                            required
                            name={"metaDescription"}
                            // onChange={(e) => onHandleChange(e, "metaDescription")}
                            // error={errors['metaDescription']}
                        />
                </CCol>
                <CCol md={12}>
                    <CForm>
                        <CFormInput
                            type="Title"
                            id="exampleFormControlInput3"
                            label="Email address"
                            placeholder="name@example.com"
                            text="Must be 8-20 characters long."
                            aria-describedby="exampleFormControlInputHelpInline"
                        />
                    </CForm>
                </CCol>
            </CRow>
        </CContainer>
    );
};

export default MagazineComponent;
